public static IEnumerable<TSource> TakeWhile<TSource>(this IEnumerable<TSource> source, Func<TSource, bool> predicate)
{
  if (source == null) // Compliant: validation is done before yielding method
    throw new ArgumentNullException(nameof(source));
  if (predicate == null)
    throw new ArgumentNullException(nameof(predicate));

  return TakeWhileCore(source, predicate);
}

private static IEnumerable<TSource> TakeWhileCore<TSource>(IEnumerable<TSource> source, Func<TSource, bool> predicate)
{
  foreach (TSource element in source)
  {
    if (predicate(element))
      yield return element;
    else
      yield break;
  }
}
